#include <stdio.h>
#include <string.h>

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        char strs[105][105];
        for (int i = 0; i < N; ++i) {
            scanf("%s", strs[i]);
        }
        char ans[105];
        for (int i = 0; i < N; ++i) {
            ans[i] = (strs[i][i] == '0') ? '1' : '0';
        }
        ans[N] = '\0';
        printf("%s\n", ans);
    }
    return 0;
}

